#include "stdio.h"
int main()
{
    int a[12][12],n,i,k;
    scanf("%d",&n);
    for (i=1;i<=n;i++)
    {
        a[1][i] = 1;
        a[i][1] = 1;
    }
    for (i=2;i<=n;i++)
    {
        for (k=2;k<=n;k++)
        {
            a[i][k] = a[i][k-1] + a[i-1][k];
        }
    }
    printf("%d",a[n][n]);
    return 0;
}

