fn main() {
    let mut input = String::new();
    std::io::stdin().read_line(&mut input).expect("INPUT::read line failed");

    let rows_and_lines = input.trim().parse::<i32>()
        .expect("ROWS_AND_LINES::parse to i32 failed");
    let mut matrix = vec![vec![i32::default(); rows_and_lines as usize]; rows_and_lines as usize];
    for i in 0..rows_and_lines {
        for j in 0..rows_and_lines {
            matrix[i as usize][j as usize] = cal(i, j);
        }
    }

    println!("{}",matrix[(rows_and_lines - 1) as usize][(rows_and_lines - 1) as usize]);
}

fn cal(i: i32, j: i32) -> i32 {
    if i == 0 || j == 0 {
        1
    }else {
        cal(i - 1, j) + cal(i, j - 1)
    }

}
